    xkb_keymap_unref(keymap);

    /* Mode: Replace */
    const char keymap_keysyms_and_actions_extras_replace[] =
        "xkb_keymap {\n"
        "  xkb_keycodes { include \"evdev\" };\n"
        "  xkb_types { include \"complete\" };\n"
        "  xkb_compat { include \"complete\" };\n"
        "  xkb_symbols {\n"
        // NOTE: Separate statements so that *all* the merge modes *really* work.
        //       Using + and | separators downgrades `replace key` to `override/
        //       augment key`.
        "    include \"pc\"\n"
        "    include \"merge_modes(keysyms_and_actions_extras_base)\"\n"
        "    replace \"merge_modes(keysyms_and_actions_extras_new)\"\n"
        "    include \"merge_modes(group2):2+merge_modes(group3):3\"\n"
        "  };\n"
        "};";
    fprintf(stderr, "*** test_merge_modes: keysyms_and_actions_extras, replace ***\n");
    keymap = test_compile_buffer(ctx, keymap_keysyms_and_actions_extras_replace,
                                 ARRAY_SIZE(keymap_keysyms_and_actions_extras_replace));
